import { Outlet } from "react-router-dom";
import Navbar from "../Navbar/Navbar";
import style from "./Layout.module.css";

function Layout() {
    return (
        <div>
            <Navbar />
            <main className={style.container_main}>
                <Outlet />
            </main>
        </div>
    )
}

export default Layout;
